using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipFile now defaults to UTF-8 and sets the
        // EFS bit. The legacy Java consumer expects Shift-JIS filenames, so
        // pass the encoding explicitly to preserve the old behaviour.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: keyed and non-keyed registrations are now
// strictly separated. A [FromKeyedServices("cache")] parameter won't
// fall back to a non-keyed registration, so register as keyed.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

